mapper.select:
SELECT *
FROM iot_device
WHERE product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND is_delete = 0
LIMIT 1

mapper.update:
UPDATE iot_device
SET status = #{status},
    updated_at = CURRENT_TIMESTAMP
WHERE product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND is_delete = 0

UPDATE iot_device
SET connect_status = #{connectStatus},
    updated_at = CURRENT_TIMESTAMP
WHERE product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND is_delete = 0

UPDATE iot_device
SET secret = #{secret},
    updated_at = CURRENT_TIMESTAMP
WHERE product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND is_delete = 0

UPDATE iot_device
SET is_delete = 1,
    updated_at = CURRENT_TIMESTAMP
WHERE product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND is_delete = 0
